const LANGUAGE_INDEX: Record<MessageBridgeLanguage, number> = { "zh-TW": 1, "zh-CN": 2, en: 3, ja: 4 };
const LOOKUP = new Map<string, NameRow>();
for (const row of PAL_NAMES) for (const value of row) LOOKUP.set(value.toLocaleLowerCase(), row);

for (const row of HUMAN_NAMES) LOOKUP.set(row[0].toLocaleLowerCase(), row);

export function localizePalName(value: string, language: MessageBridgeLanguage): string {
  const clean = value.trim();
  const withoutBoss = clean.replace(/^BOSS_/i, "");
  const baseId = withoutBoss.replace(/_otomo$/i, "");
  const row = [clean, withoutBoss, baseId].map((candidate) => LOOKUP.get(candidate.toLocaleLowerCase())).find(Boolean);
  return row?.[LANGUAGE_INDEX[language]] || clean;
}
